  "description": "Aplikasi penyusun Standar Operasional Prosedur (SOP) otomatis berbasis AI sesuai standar format Yayasan As-Syifa Al-Khoeriyyah."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

