export enum SymbolType {
  TERMINATOR = 'TERMINATOR', // Start/End (Rounded Rect)
  PROCESS = 'PROCESS',       // Action (Rect)
  DECISION = 'DECISION',     // Question (Diamond)
  DOCUMENT = 'DOCUMENT'      // Document (Wave bottom)
}

export interface SOPStep {
  id: string;
  activity: string;
  executorRole: string; // The specific role name (matches a column)
  requirements: string;
  time: string;
  output: string;
  symbol: SymbolType;
}

export interface SOPData {
  title: string;
  documentNumber: string;
  revisionDate: string;
  effectiveDate: string;
  department: string;

  // Signatories
  approvedBy: string; // Name
  approvedByTitle: string; // e.g. Ketua Umum
  checkedBy: string; // Name
  checkedByTitle: string; // e.g. Sekretaris
  madeBy: string; // Name
  madeByTitle: string; // e.g. Kepala Bagian

  legalBasis: string[]; // Dasar Hukum
  relatedSOPs: string[]; // Keterkaitan

  // Dynamic Columns for the "Pelaksana" section
  executorColumns: string[]; 

  steps: SOPStep[];
}

export const DEFAULT_SOP_DATA: SOPData = {
  title: "JUDUL PROSEDUR",
  documentNumber: "001/SOP/...",
  revisionDate: new Date().toISOString().split('T')[0],
  effectiveDate: new Date().toISOString().split('T')[0],
  department: "BAGIAN ...",
  approvedBy: "H. Abdullah, M.Sc",
  approvedByTitle: "Ketua Umum",
  checkedBy: "Budi Mulia",
  checkedByTitle: "Sekretaris",
  madeBy: "Nama Pembuat",
  madeByTitle: "Kepala Bagian",
  legalBasis: ["AD/ART Yayasan As-syifa Al-khoeriyyah"],
  relatedSOPs: ["-"],
  executorColumns: ["Pemohon", "Atasan", "HRD"],
  steps: []
};

import { GoogleGenAI, Type, SchemaType } from "@google/genai";
import { SOPData, SymbolType } from "../types";

const parseJSON = (text: string) => {
    try {
        const start = text.indexOf('{');
        const end = text.lastIndexOf('}');
        if (start === -1 || end === -1) return null;
        return JSON.parse(text.substring(start, end + 1));
    } catch (e) {
        console.error("Failed to parse JSON", e);
        return null;
    }
}

export const generateSOPContent = async (
  topic: string, 
  description: string,
  apiKey: string
): Promise<Partial<SOPData> | null> => {
  if (!apiKey) return null;

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    You are an expert SOP (Standard Operating Procedure) consultant for "Yayasan As-Syifa Al-Khoeriyyah".
    Your task is to convert a user's rough process description into a structured SOP JSON format.

    The Format requires:
    1. A Title.
    2. A list of Executor Roles (Pelaksana) involved (e.g., Staff, Kepala Bagian, HRD).
    3. A list of sequential Steps. 
       - Each step must be assigned to ONE specific 'executorRole' from the list you created.
       - Each step has standard requirements (Standar Baku): Requirements, Time (minutes/days), Output.
       - Each step has a flowchart symbol type: 'TERMINATOR' (Start/End), 'PROCESS' (Action), 'DECISION' (Branching/YesNo), 'DOCUMENT'.
    4. Legal Basis (Dasar Hukum) - suggest generic relevant laws or foundation rules.
    5. Related SOPs (Keterkaitan).

    Input Topic: "${topic}"
    Input Description: "${description}"

    Return ONLY raw JSON.
  `;

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING },
      department: { type: Type.STRING, description: "The unit/department likely responsible" },
      executorColumns: { 
        type: Type.ARRAY, 
        items: { type: Type.STRING },
        description: "List of distinct roles/titles involved in the flowchart columns"
      },
      legalBasis: { type: Type.ARRAY, items: { type: Type.STRING } },
      relatedSOPs: { type: Type.ARRAY, items: { type: Type.STRING } },
      steps: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            activity: { type: Type.STRING, description: "Description of the activity" },
            executorRole: { type: Type.STRING, description: "Must match one value from executorColumns" },
            requirements: { type: Type.STRING, description: "Documents or prerequisites needed" },
            time: { type: Type.STRING, description: "Estimated duration" },
            output: { type: Type.STRING, description: "Result of the step (e.g. Surat, Acc)" },
            symbol: { type: Type.STRING, enum: [SymbolType.TERMINATOR, SymbolType.PROCESS, SymbolType.DECISION, SymbolType.DOCUMENT] }
          }
        }
      }
    },
    required: ["title", "department", "executorColumns", "steps", "legalBasis"]
  };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-latest',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      }
    });

    const text = response.text;
    if (!text) return null;

    const data = parseJSON(text);
    return data;

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React from 'react';
import { SymbolType } from '../types';

interface SymbolProps {
  type: SymbolType;
  className?: string;
}

export const SymbolIcon: React.FC<SymbolProps> = ({ type, className = "w-8 h-8" }) => {
  const strokeColor = "#000";
  const strokeWidth = 1.5;
  const fillColor = "#fff";

  switch (type) {
    case SymbolType.TERMINATOR:
      // Capsule shape
      return (
        <svg viewBox="0 0 100 50" className={className}>
          <rect x="2" y="2" width="96" height="46" rx="23" fill={fillColor} stroke={strokeColor} strokeWidth={strokeWidth} />
        </svg>
      );
    case SymbolType.DECISION:
      // Diamond
      return (
        <svg viewBox="0 0 100 50" className={className}>
          <polygon points="50,2 98,25 50,48 2,25" fill={fillColor} stroke={strokeColor} strokeWidth={strokeWidth} />
        </svg>
      );
    case SymbolType.DOCUMENT:
      // Rectangle with wavy bottom
      return (
        <svg viewBox="0 0 100 50" className={className}>
          <path d="M5,2 L95,2 L95,40 Q75,50 50,40 T5,40 Z" fill={fillColor} stroke={strokeColor} strokeWidth={strokeWidth} />
        </svg>
      );
    case SymbolType.PROCESS:
    default:
      // Rectangle
      return (
        <svg viewBox="0 0 100 50" className={className}>
          <rect x="2" y="2" width="96" height="46" fill={fillColor} stroke={strokeColor} strokeWidth={strokeWidth} />
        </svg>
      );
  }
};

import React, { useState } from 'react';
