};

import React, { useState, useEffect } from 'react';
import { generateSOPContent } from './services/geminiService';
import { SOPData, DEFAULT_SOP_DATA } from './types';
import { SOPEditor } from './components/SOPEditor';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [stage, setStage] = useState<'INPUT' | 'GENERATING' | 'EDIT'>('INPUT');
  const [topic, setTopic] = useState('');
  const [description, setDescription] = useState('');
  const [sopData, setSopData] = useState<SOPData>(DEFAULT_SOP_DATA);
  const [apiKey, setApiKey] = useState(process.env.API_KEY || '');
  const [hasEnvKey, setHasEnvKey] = useState(false);

  useEffect(() => {
    if (process.env.API_KEY) {
        setApiKey(process.env.API_KEY);
        setHasEnvKey(true);
    } else {
        // Fallback for demo purposes if environment variable isn't injected in the build environment
        // In a real scenario, we strictly rely on env vars or a secure backend proxy.
        // For this frontend-only artifact generation, we might ask user.
        // But adhering to instructions: "The API key must be obtained exclusively from the environment variable"
        // If it's empty, the app will likely fail to generate.
    }
  }, []);


  const handleGenerate = async () => {
    if (!topic) return;
    setStage('GENERATING');

    try {
      const generated = await generateSOPContent(topic, description, apiKey);
      if (generated) {
        setSopData(prev => ({
          ...prev,
          ...generated,
          // Ensure defaults for missing fields
          documentNumber: prev.documentNumber,
          revisionDate: prev.revisionDate,
          effectiveDate: prev.effectiveDate,
          approvedBy: prev.approvedBy,
          steps: generated.steps?.map((s, i) => ({
             ...s,
             id: i.toString(),
             symbol: s.symbol as any || 'PROCESS' // Type cast safely
          })) || []
        }));
      }
      setStage('EDIT');
    } catch (error) {
      alert("Gagal membuat SOP. Pastikan API Key valid atau coba lagi.");
      setStage('INPUT');
    }
  };

  const handlePrint = () => {
    window.print();
  };

  if (stage === 'INPUT') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 p-4">
        <div className="bg-white p-8 rounded-xl shadow-lg w-full max-w-2xl border-t-4 border-green-600">
          <div className="flex items-center justify-center mb-6">
             <div className="w-12 h-12 bg-green-100 rounded-full flex items-center justify-center mr-4">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
               </svg>
             </div>
             <div>
                <h1 className="text-2xl font-bold text-gray-800">SOP Generator As-Syifa</h1>
                <p className="text-gray-500 text-sm">Buat Standar Operasional Prosedur otomatis dengan AI</p>
             </div>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Judul / Topik SOP</label>
              <input
                type="text"
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-green-500 outline-none transition"
                placeholder="Contoh: Pengajuan Cuti Karyawan"
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Deskripsi Singkat Proses (Opsional)</label>
              <textarea
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-green-500 outline-none transition h-32 resize-none"
                placeholder="Jelaskan secara kasar alurnya, misal: Staff isi form, Supervisor acc, HRD input data..."
                value={description}
                onChange={(e) => setDescription(e.target.value)}
              />
            </div>

            <button
              onClick={handleGenerate}
              disabled={!topic || !apiKey}
              className={`w-full py-3 rounded-lg text-white font-semibold shadow-md transition-all
