             <polygon points="10,24 6,16 14,16" fill={strokeColor} />
           </svg>
        </div>
      );
    }

    // Different Column (Curved/Orthogonal)
    // We assume columns have equal width for this visual hack to work nicely.
    // We calculate width based on % of the current cell.

    const direction = colDiff > 0 ? 1 : -1;
    const absDiff = Math.abs(colDiff);

    // SVG Dimensions
    // Width: spans from center of current to center of target.
    // 100% width = 1 cell width (approx).
    // Total width needed = (absDiff * 100)%

    // We position the SVG starting from the center of the current cell.
    const svgWidthPercent = absDiff * 100; 
    const svgLeftPercent = direction > 0 ? 50 : 50 - svgWidthPercent; 

    // Path logic
    // Start: (direction > 0) ? 0 : 100% (relative to SVG), y=0
    // End:   (direction > 0) ? 100% : 0 (relative to SVG), y=Height

    return (
      <div 
        className="absolute bottom-[-20px] h-[30px] z-10 pointer-events-none"
        style={{
            left: `${svgLeftPercent}%`,
            width: `${svgWidthPercent}%`
        }}
