             {/* 
                Path: 
                M startX 0 
                L startX 15 (Go down a bit)
                L endX 15   (Go across)
                L endX 22   (Go down to arrow head)
             */}
             {(() => {
                 // Coordinate system inside viewBox is 0 to svgWidthPercent
                 const startX = direction > 0 ? 0 : svgWidthPercent;
                 const endX = direction > 0 ? svgWidthPercent : 0;

                 return (
                    <>
                        <path 
                            d={`M ${startX} 0 L ${startX} 15 L ${endX} 15 L ${endX} 22`}
                            fill="none"
                            stroke={strokeColor}
                            strokeWidth={strokeWidth}
                        />
                        <polygon 
                            points={`${endX},28 ${endX-3},20 ${endX+3},20`} 
                            fill={strokeColor} 
                        />
                    </>
                 );
             })()}
