               />
            </td>
          </tr>
          <tr>
            <td className="border border-black px-2 py-1 font-semibold bg-gray-50 text-black">Tanggal Berlaku</td>
            <td className="border border-black px-2 py-1">
              <span className="mr-1 text-black">:</span>
               <input 
                  type="date"
                  className="bg-transparent focus:outline-none text-black" 
