import React, { useState, useEffect } from 'react';
import { generateSOPContent } from './services/geminiService';
import { SOPData, DEFAULT_SOP_DATA } from './types';
import { SOPEditor } from './components/SOPEditor';

const App: React.FC = () => {
  const [stage, setStage] = useState<'INPUT' | 'GENERATING' | 'EDIT'>('INPUT');
  const [topic, setTopic] = useState('');
  const [description, setDescription] = useState('');
  const [sopData, setSopData] = useState<SOPData>(DEFAULT_SOP_DATA);

  // Check for API Key presence for UI feedback only
  const hasApiKey = !!process.env.API_KEY;

  // Update document title based on SOP title for better PDF filenames
  useEffect(() => {
    if (sopData.title && sopData.title !== "JUDUL PROSEDUR") {
      document.title = sopData.title;
    } else {
      document.title = "Generator SOP As-Syifa";
    }
  }, [sopData.title]);

  const handleGenerate = async () => {
    if (!topic) return;
    setStage('GENERATING');

    try {
      const generated = await generateSOPContent(topic, description);
      if (generated) {
        setSopData(prev => ({
          ...prev,
          ...generated,
          // Ensure defaults for missing fields
          documentNumber: prev.documentNumber,
          revisionDate: prev.revisionDate,
          effectiveDate: prev.effectiveDate,
          approvedBy: prev.approvedBy,
          steps: generated.steps?.map((s, i) => ({
             ...s,
             id: i.toString(),
             symbol: s.symbol as any || 'PROCESS' // Type cast safely
          })) || []
        }));
        setStage('EDIT');
      } else {
        throw new Error("No data generated");
      }
    } catch (error) {
      console.error(error);
      alert("Gagal membuat SOP. Pastikan API Key valid atau coba lagi.");
      setStage('INPUT');
    }
  };

  const handlePrint = () => {
    window.print();
  };

  if (stage === 'INPUT') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-4 relative">
        {/* Background Image */}
        <div 
          className="absolute inset-0 z-0"
          style={{
            backgroundImage: "url('https://i0.wp.com/smkit.assyifa.sch.id/wp-content/uploads/2023/10/a_11zon.jpg?resize=600%2C450&ssl=1')",
            backgroundSize: 'cover',
            backgroundPosition: 'center',
          }}
        />
        {/* Maroon Overlay (Opacity 50%) */}
        <div className="absolute inset-0 z-0 bg-[#800000] opacity-50"></div>

        <div className="bg-white p-8 rounded-xl shadow-lg w-full max-w-2xl border-t-4 border-green-600 z-10 relative">
          <div className="flex items-center justify-center mb-6">
             <div className="w-12 h-12 bg-green-100 rounded-full flex items-center justify-center mr-4">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
               </svg>
             </div>
             <div>
                <h1 className="text-2xl font-bold text-gray-800">Generator SOP As-Syifa</h1>
                <p className="text-gray-500 text-sm">Buat Standar Operasional Prosedur otomatis dengan AI</p>
             </div>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Judul / Topik SOP</label>
              <input
                type="text"
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-green-500 outline-none transition"
                placeholder="Contoh: Pengajuan Cuti Karyawan"
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Deskripsi Singkat Proses (Opsional)</label>
              <textarea
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-green-500 outline-none transition h-32 resize-none"
                placeholder="Jelaskan secara kasar alurnya, misal: Staff isi form, Supervisor acc, HRD input data..."
                value={description}
                onChange={(e) => setDescription(e.target.value)}
              />
            </div>

            <button
              onClick={handleGenerate}
              disabled={!topic || !hasApiKey}
              className={`w-full py-3 rounded-lg text-white font-semibold shadow-md transition-all
                 ${(!topic || !hasApiKey) ? 'bg-gray-400 cursor-not-allowed' : 'bg-green-600 hover:bg-green-700 hover:shadow-lg transform hover:-translate-y-0.5'}
              `}
            >
              {!hasApiKey ? 'API Key Missing (Check env)' : 'Buat SOP Sekarang'}
            </button>

            {!hasApiKey && (
                 <p className="text-xs text-red-500 text-center mt-2">
                    Error: API Key tidak ditemukan. Pastikan `process.env.API_KEY` dikonfigurasi.
                 </p>
            )}
          </div>
        </div>

        {/* Footer Credit */}
        <div className="z-10 mt-6 text-white text-sm font-medium drop-shadow-md text-center">
             Ryan Mustami Nugroho. Guru SMK-IT As-Syifa Boarding School . 2026
        </div>
      </div>
    );
  }

  if (stage === 'GENERATING') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50">
        <div className="flex flex-col items-center">
            <div className="w-16 h-16 border-4 border-green-200 border-t-green-600 rounded-full animate-spin mb-4"></div>
            <h2 className="text-xl font-semibold text-gray-700">Sedang Menyusun SOP...</h2>
            <p className="text-gray-500">AI sedang menganalisis alur kerja dan format As-Syifa.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col print:block print:h-auto print:bg-white">
      {/* Top Bar - No Print */}
      <div className="no-print bg-white shadow-sm border-b border-gray-200 p-4 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
             <button onClick={() => setStage('INPUT')} className="text-gray-500 hover:text-gray-700 text-sm font-medium">
               &larr; Kembali
             </button>
             <h1 className="font-bold text-gray-800">Preview & Edit SOP</h1>
          </div>
          <div className="flex gap-3">
             <div className="text-xs text-gray-500 flex items-center bg-yellow-50 px-3 py-1 rounded border border-yellow-200">
                <svg className="w-4 h-4 mr-1 text-yellow-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                Klik simbol flowchart untuk menggantinya
             </div>
             <button 
               onClick={handlePrint}
               className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 shadow transition-colors"
             >
               <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                 <path fillRule="evenodd" d="M3 17a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zm3.293-7.707a1 1 0 011.414 0L9 10.586V3a1 1 0 112 0v7.586l1.293-1.293a1 1 0 111.414 1.414l-3 3a1 1 0 01-1.414 0l-3-3a1 1 0 010-1.414z" clipRule="evenodd" />
               </svg>
               Cetak / Simpan PDF
             </button>
          </div>
        </div>
      </div>

      <div className="flex-1 p-8 overflow-auto print:p-0 print:overflow-visible print:h-auto">
         <SOPEditor data={sopData} onChange={setSopData} />
      </div>
    </div>
  );
};

export default App;

