                ))}
                <th className="border border-black p-1 bg-green-100 w-[10%] text-black print:bg-green-100">Mutu Baku</th>
                <th className="border border-black p-1 bg-green-100 w-[5%] text-black print:bg-green-100">Waktu</th>
                <th className="border border-black p-1 bg-green-100 w-[10%] text-black print:bg-green-100">Output</th>
            </tr>
        </thead>
        <tbody>
            {data.steps.map((step, index) => (
                <tr key={index}>
                    <td className="border border-black p-2 text-center align-middle text-black">{index + 1}</td>
                    <td className="border border-black p-2 align-middle">
                        <AutoResizeTextarea
                            className="w-full bg-transparent focus:outline-none text-xs text-black"
                            value={step.activity}
                            onChange={(e: any) => updateStep(index, 'activity', e.target.value)}
