                <AutoResizeTextarea
                    className="w-full text-center font-bold text-[#1C4D8D] text-xs bg-transparent border-none focus:ring-0 focus:outline-none print:text-[#1C4D8D] placeholder-[#1C4D8D]/50 resize-none overflow-hidden"
                    value={data.organizationName || "Nama Lembaga/Perusahaan"}
                    onChange={(e: any) => updateField('organizationName', e.target.value)}
                    placeholder="Nama Lembaga/Perusahaan"
                    onClick={(e) => e.stopPropagation()} 
                />
              </div>
            </td>

            {/* Title Section */}
            <td rowSpan={4} className="border border-[#1C4D8D] p-2 w-[30%] text-center align-middle bg-[#F3F4F6] print:bg-[#F3F4F6]">
                <AutoResizeTextarea
                    className="w-full text-center font-bold text-lg uppercase bg-transparent border-none focus:ring-1 focus:ring-[#1C4D8D] text-[#0F2854] placeholder-gray-400"
                    value={data.department}
                    onChange={(e: any) => updateField('department', e.target.value)}
                    placeholder="BAGIAN..."
                />
            </td>

            {/* Document Details Section */}
            <td className="border border-[#1C4D8D] px-2 py-1 w-[15%] font-semibold bg-[#F3F4F6] text-[#0F2854] print:bg-[#F3F4F6]">No. SOP/Dokumen</td>
            <td className="border border-[#1C4D8D] px-2 py-1 w-[35%]">
               <span className="mr-1 text-[#0F2854]">:</span>
               <input 
                  className="w-[90%] bg-transparent focus:outline-none text-[#0F2854]" 
                  value={data.documentNumber}
                  onChange={(e) => updateField('documentNumber', e.target.value)}
               />
            </td>
          </tr>
          <tr>
            <td className="border border-[#1C4D8D] px-2 py-1 font-semibold bg-[#F3F4F6] text-[#0F2854] print:bg-[#F3F4F6]">Revisi / Tanggal</td>
            <td className="border border-[#1C4D8D] px-2 py-1">
               <span className="mr-1 text-[#0F2854]">:</span>
               <input 
                  type="date"
                  className="bg-transparent focus:outline-none text-[#0F2854]" 
                  value={data.revisionDate}
                  onChange={(e) => updateField('revisionDate', e.target.value)}
               />
            </td>
          </tr>
          <tr>
            <td className="border border-[#1C4D8D] px-2 py-1 font-semibold bg-[#F3F4F6] text-[#0F2854] print:bg-[#F3F4F6]">Tanggal Berlaku</td>
            <td className="border border-[#1C4D8D] px-2 py-1">
              <span className="mr-1 text-[#0F2854]">:</span>
               <input 
                  type="date"
                  className="bg-transparent focus:outline-none text-[#0F2854]" 
                  value={data.effectiveDate}
                  onChange={(e) => updateField('effectiveDate', e.target.value)}
               />
            </td>
          </tr>
          <tr>
            <td className="border border-[#1C4D8D] px-2 py-1 font-semibold bg-[#F3F4F6] text-[#0F2854] print:bg-[#F3F4F6]">Halaman</td>
            <td className="border border-[#1C4D8D] px-2 py-1 text-[#0F2854]">
              <span className="mr-1">:</span> 1 dari 1
            </td>
          </tr>

          {/* Signatures Row */}
          <tr>
             <td colSpan={4} className="border border-[#1C4D8D] p-0">
                <div className="flex w-full">
                    <div className="flex-1 border-r border-[#1C4D8D] p-2 flex flex-col items-center">
                        <span className="text-[10px] mb-8 text-[#0F2854]">Disahkan oleh:</span>
                        <input 
                            className="text-center font-bold text-[11px] w-full bg-transparent mb-1 text-[#0F2854]"
                            value={data.approvedBy}
                            onChange={(e) => updateField('approvedBy', e.target.value)}
                        />
                         <input 
                            className="text-center text-[10px] w-full bg-transparent text-[#0F2854]"
                            value={data.approvedByTitle}
                            onChange={(e) => updateField('approvedByTitle', e.target.value)}
                        />
                    </div>
                    <div className="flex-1 border-r border-[#1C4D8D] p-2 flex flex-col items-center">
                        <span className="text-[10px] mb-8 text-[#0F2854]">Diperiksa oleh:</span>
                         <input 
                            className="text-center font-bold text-[11px] w-full bg-transparent mb-1 text-[#0F2854]"
                            value={data.checkedBy}
                            onChange={(e) => updateField('checkedBy', e.target.value)}
                        />
                         <input 
                            className="text-center text-[10px] w-full bg-transparent text-[#0F2854]"
                            value={data.checkedByTitle}
                            onChange={(e) => updateField('checkedByTitle', e.target.value)}
                        />
                    </div>
                    <div className="flex-1 border-r border-[#1C4D8D] p-2 flex flex-col items-center">
                        <span className="text-[10px] mb-8 text-[#0F2854]">Dibuat oleh:</span>
                         <input 
                            className="text-center font-bold text-[11px] w-full bg-transparent mb-1 text-[#0F2854]"
                            value={data.madeBy}
                            onChange={(e) => updateField('madeBy', e.target.value)}
                        />
                         <input 
                            className="text-center text-[10px] w-full bg-transparent text-[#0F2854]"
                            value={data.madeByTitle}
                            onChange={(e) => updateField('madeByTitle', e.target.value)}
                        />
                    </div>
                    <div className="flex-1 p-2 flex flex-col items-center justify-center bg-[#1C4D8D] text-white print:bg-[#1C4D8D] print:text-white header-bg">
                        <div className="text-center font-bold">STANDARD OPERASIONAL PROSEDUR</div>
                        <AutoResizeTextarea
                            className="text-center font-bold text-sm w-full bg-transparent text-white placeholder-white/70 uppercase mt-1"
                            value={data.title}
                            onChange={(e: any) => updateField('title', e.target.value)}
                        />
                    </div>
                </div>
             </td>
          </tr>
        </tbody>
      </table>

      {/* --- INFO TABLE --- */}
      <table className="w-full border-collapse border border-[#1C4D8D] mb-4 text-[11px] text-[#0F2854]">
         <thead>
            <tr>
                <th className="border border-[#1C4D8D] p-1 w-1/2 bg-[#BDE8F5] uppercase text-[#0F2854] print:bg-[#BDE8F5]">Dasar Hukum</th>
                <th className="border border-[#1C4D8D] p-1 w-1/2 bg-[#BDE8F5] uppercase text-[#0F2854] print:bg-[#BDE8F5]">Keterkaitan</th>
            </tr>
         </thead>
         <tbody>
             <tr>
                 <td className="border border-[#1C4D8D] p-2 align-top">
                    <AutoResizeTextarea 
                        className="w-full min-h-[6rem] bg-transparent focus:outline-none text-[#0F2854]"
                        value={data.legalBasis.join('\n')}
                        onChange={(e: any) => updateField('legalBasis', e.target.value.split('\n'))}
                    />
                 </td>
                 <td className="border border-[#1C4D8D] p-2 align-top">
                    <AutoResizeTextarea
                        className="w-full min-h-[6rem] bg-transparent focus:outline-none text-[#0F2854]"
                        value={data.relatedSOPs.join('\n')}
                        onChange={(e: any) => updateField('relatedSOPs', e.target.value.split('\n'))}
                    />
                 </td>
             </tr>
         </tbody>
      </table>

      {/* --- MAIN PROCESS TABLE (SWIMLANE HYBRID) --- */}
      <table className="w-full border-collapse border border-[#1C4D8D] text-[11px] text-[#0F2854] table-fixed relative">
        <thead className="bg-[#4988C4] print:bg-[#4988C4] text-white print:text-white">
            <tr>
                <th rowSpan={2} className="border border-[#1C4D8D] p-1 w-[4%] bg-[#4988C4] print:bg-[#4988C4]">NO</th>
                <th rowSpan={2} className="border border-[#1C4D8D] p-1 w-[20%] bg-[#4988C4] print:bg-[#4988C4]">AKTIVITAS</th>
                <th colSpan={data.executorColumns.length} className="border border-[#1C4D8D] p-1 bg-[#4988C4] print:bg-[#4988C4] relative group">
                    PELAKSANA
                    <button 
                        onClick={addExecutorColumn}
                        className="no-print absolute right-1 top-1 bg-white text-[#1C4D8D] w-5 h-5 rounded-full flex items-center justify-center text-xs hover:bg-[#BDE8F5] shadow font-bold"
                        title="Tambah Kolom"
                    >
                        +
                    </button>
                </th>
                <th colSpan={3} className="border border-[#1C4D8D] p-1 bg-[#4988C4] print:bg-[#4988C4]">STANDAR BAKU</th>
            </tr>
            <tr>
                {data.executorColumns.map((col, idx) => (
                    <th key={idx} className="border border-[#1C4D8D] p-1 min-w-[80px] bg-[#BDE8F5] text-[#0F2854] print:bg-[#BDE8F5] print:text-[#0F2854] relative group">
                        <AutoResizeTextarea
                            value={col} 
                            onChange={(e: any) => updateExecutorColumn(idx, e.target.value)}
                            className="w-full text-center bg-transparent font-bold focus:outline-none text-[#0F2854]"
                        />
                         <button 
                            onClick={() => removeExecutorColumn(idx)}
                            className="no-print hidden group-hover:flex absolute -top-2 -right-2 bg-red-500 text-white w-4 h-4 rounded-full items-center justify-center text-[10px] hover:bg-red-600 shadow z-50"
                            title="Hapus Kolom"
                        >
                            x
                        </button>
                    </th>
                ))}
                <th className="border border-[#1C4D8D] p-1 bg-[#BDE8F5] w-[10%] text-[#0F2854] print:bg-[#BDE8F5] print:text-[#0F2854]">Mutu Baku</th>
                <th className="border border-[#1C4D8D] p-1 bg-[#BDE8F5] w-[5%] text-[#0F2854] print:bg-[#BDE8F5] print:text-[#0F2854]">Waktu</th>
                <th className="border border-[#1C4D8D] p-1 bg-[#BDE8F5] w-[10%] text-[#0F2854] print:bg-[#BDE8F5] print:text-[#0F2854]">Output</th>
            </tr>
        </thead>
        <tbody className="relative">
            {data.steps.map((step, index) => (
                <tr 
                    key={index} 
                    className={`transition-colors ${dragState.isDragging && hoveredRowIndex === index ? 'bg-[#BDE8F5] ring-2 ring-[#4988C4] ring-inset z-10' : ''}`}
                    onMouseEnter={() => dragState.isDragging && setHoveredRowIndex(index)}
                    onMouseLeave={() => dragState.isDragging && setHoveredRowIndex(null)}
                >
                    <td className="border border-[#1C4D8D] p-2 text-center align-middle text-[#0F2854]">{index + 1}</td>
                    <td className="border border-[#1C4D8D] p-2 align-middle">
                        <AutoResizeTextarea
                            className="w-full bg-transparent focus:outline-none text-xs text-[#0F2854]"
                            value={step.activity}
                            onChange={(e: any) => updateStep(index, 'activity', e.target.value)}
                        />
                    </td>

                    {/* Executor Swimlanes */}
                    {data.executorColumns.map((col, colIdx) => {
                         const isExecutor = step.executorRole === col;
                         return (
                            <td key={col} className="border border-[#1C4D8D] p-1 relative align-middle overflow-visible">
                                {isExecutor && (
                                    <div 
                                        id={`node-${index}-${colIdx}`} // Unique ID for Coordinates
                                        className="flex flex-col items-center justify-center relative h-full py-4 min-h-[80px] group/cell"
                                    >
                                        <div className="group relative cursor-pointer" title="Klik untuk mengubah simbol">
                                            <SymbolIcon type={step.symbol} className="w-10 h-8 text-[#0F2854]" />
                                            {/* Symbol Menu */}
                                            <div className="absolute hidden group-hover:flex flex-col bg-white border border-[#1C4D8D] z-50 -top-10 left-0 p-1 rounded shadow w-max">
                                                {Object.values(SymbolType).map(t => (
                                                    <div key={t} onClick={() => updateStep(index, 'symbol', t)} className="p-2 hover:bg-[#BDE8F5] text-[9px] text-[#0F2854] cursor-pointer">
                                                        {t}
                                                    </div>
                                                ))}
                                            </div>
                                        </div>

                                        {/* Column Mover (Visible on hover of the cell) */}
                                        <div className="no-print absolute top-0 right-0 hidden group-hover/cell:block z-40">
                                            <select 
                                                className="opacity-0 hover:opacity-100 absolute right-0 top-0 w-full h-full cursor-pointer"
                                                title="Pindahkan ke kolom lain"
                                                value={step.executorRole}
                                                onChange={(e) => updateStep(index, 'executorRole', e.target.value)}
                                            >
                                                {data.executorColumns.map(c => (
                                                    <option key={c} value={c}>{c}</option>
                                                ))}
                                            </select>
                                            <div className="text-[9px] bg-[#BDE8F5] px-1 rounded text-[#1C4D8D] border border-[#1C4D8D] cursor-pointer hover:bg-[#4988C4] hover:text-white">
                                                Move
                                            </div>
                                        </div>

                                        {/* Config Button & Menu for Decision (NO Branch) */}
                                        {step.symbol === SymbolType.DECISION && (
                                            <>
                                                <button
                                                    className="no-print absolute top-0 right-0 m-1 w-5 h-5 bg-white border border-gray-300 rounded shadow-sm flex items-center justify-center opacity-0 group-hover/cell:opacity-100 transition-opacity z-50 hover:bg-gray-50 text-gray-500"
                                                    onClick={(e) => {
                                                        e.stopPropagation();
                                                        setActiveDecisionMenuIndex(activeDecisionMenuIndex === index ? null : index);
                                                    }}
                                                    title="Atur target 'TIDAK'"
                                                >
                                                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3 h-3">
                                                      <path fillRule="evenodd" d="M11.49 3.17c-.38-1.56-2.6-1.56-2.98 0a1.532 1.532 0 01-2.286.948c-1.372-.836-2.942.734-2.106 2.106.54.886.061 2.042-.947 2.287-1.561.379-1.561 2.6 0 2.978a1.532 1.532 0 01.947 2.287c-.836 1.372.734 2.942 2.106 2.106a1.532 1.532 0 012.287.947c.379 1.561 2.6 1.561 2.978 0a1.533 1.533 0 012.287-.947c1.372.836 2.942-.734 2.106-2.106a1.533 1.533 0 01.947-2.287c1.561-.379 1.561-2.6 0-2.978a1.532 1.532 0 01-.947-2.287c.836-1.372-.734-2.942-2.106-2.106a1.532 1.532 0 01-2.287-.947zM10 13a3 3 0 100-6 3 3 0 000 6z" clipRule="evenodd" />
                                                    </svg>
                                                </button>

                                                {activeDecisionMenuIndex === index && (
                                                    <div 
                                                        className="no-print absolute top-8 left-1/2 transform -translate-x-1/2 z-[60] bg-white border border-red-300 p-2 rounded shadow-xl text-[10px] min-w-[140px]"
                                                        onClick={(e) => e.stopPropagation()}
                                                    >
                                                        <div className="flex justify-between items-center mb-1 pb-1 border-b border-gray-100">
                                                            <span className="font-bold text-red-600">Jika TIDAK:</span>
                                                            <button 
                                                                onClick={() => setActiveDecisionMenuIndex(null)}
                                                                className="text-gray-400 hover:text-gray-600 font-bold px-1"
                                                            >
                                                                ✕
                                                            </button>
                                                        </div>
                                                        <select
                                                            className="w-full border border-gray-300 rounded px-1 py-1 bg-gray-50 focus:outline-none focus:border-red-400 mb-1"
                                                            value={step.decisionNoTargetRow || ''}
                                                            onChange={(e) => updateStep(index, 'decisionNoTargetRow', e.target.value)}
                                                        >
                                                            <option value="">(Pilih Langkah)</option>
                                                            {data.steps.map((_, i) => (
                                                                <option key={i} value={(i + 1).toString()}>
                                                                    Langkah {i + 1}
                                                                </option>
                                                            ))}
                                                        </select>
                                                        <div className="text-[9px] text-gray-400 italic">
                                                            Atau tarik titik merah.
                                                        </div>
                                                    </div>
                                                )}
                                            </>
                                        )}

                                        {renderDragHandle(step, index)}
                                    </div>
                                )}
                            </td>
                         );
                    })}

                    <td className="border border-[#1C4D8D] p-2 align-middle">
                        <AutoResizeTextarea
                            className="w-full bg-transparent text-center focus:outline-none text-[#0F2854]"
                            value={step.requirements}
                            onChange={(e: any) => updateStep(index, 'requirements', e.target.value)}
                        />
                    </td>
                    <td className="border border-[#1C4D8D] p-2 align-middle text-center">
                        <AutoResizeTextarea
                             className="w-full bg-transparent text-center focus:outline-none text-[#0F2854]"
                             value={step.time}
                             onChange={(e: any) => updateStep(index, 'time', e.target.value)}
                        />
                    </td>
                    <td className="border border-[#1C4D8D] p-2 align-middle">
                         <AutoResizeTextarea
                            className="w-full bg-transparent text-center focus:outline-none text-[#0F2854]"
                            value={step.output}
                            onChange={(e: any) => updateStep(index, 'output', e.target.value)}
                        />
                    </td>
                </tr>
            ))}
        </tbody>
      </table>

      {/* Add Step Button (Hidden in Print) */}
      <div className="no-print mt-4 flex justify-center">
        <button 
            onClick={() => {
                const newStep = {
                    id: Date.now().toString(),
                    activity: "Kegiatan baru...",
                    executorRole: data.executorColumns[0],
                    requirements: "-",
                    time: "5 menit",
                    output: "-",
                    symbol: SymbolType.PROCESS
                };
                updateField('steps', [...data.steps, newStep]);
            }}
            className="px-4 py-2 bg-[#1C4D8D] text-white rounded hover:bg-[#0F2854] text-sm flex items-center gap-2 shadow"
        >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" />
            </svg>
            Tambah Langkah
        </button>
      </div>

    </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useLayoutEffect } from 'react';
import { SOPData, SymbolType } from '../types';
import { SymbolIcon } from './SymbolIcon';

interface SOPEditorProps {
  data: SOPData;
  onChange: (newData: SOPData) => void;
}

// Helper Component for Auto-Resizing Textarea
const AutoResizeTextarea: React.FC<React.TextareaHTMLAttributes<HTMLTextAreaElement>> = ({ value, onChange, className, ...props }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto'; 
      textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  }, [value]);

  return (
    <textarea
      ref={textareaRef}
      value={value}
      onChange={onChange}
      className={`${className} overflow-hidden resize-none block`}
      rows={1}
      {...props}
    />
  );
};

export const SOPEditor: React.FC<SOPEditorProps> = ({ data, onChange }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Drag and Drop Logic State
  const [dragState, setDragState] = useState<{
    isDragging: boolean;
    sourceIndex: number | null;
    startX: number;
    startY: number;
    currentX: number;
    currentY: number;
  }>({
    isDragging: false,
    sourceIndex: null,
    startX: 0,
    startY: 0,
    currentX: 0,
    currentY: 0,
  });

  const [hoveredRowIndex, setHoveredRowIndex] = useState<number | null>(null);
  const [connectionPaths, setConnectionPaths] = useState<React.ReactNode[]>([]);
  const [activeDecisionMenuIndex, setActiveDecisionMenuIndex] = useState<number | null>(null);

  // State to track layout changes (for resizing textareas causing vertical shifts)
  const [layoutVersion, setLayoutVersion] = useState(0);

  // Monitor container size changes to trigger path recalculation
  useEffect(() => {
    if (!containerRef.current) return;

    const observer = new ResizeObserver(() => {
       // Debounce slightly or just trigger update
       requestAnimationFrame(() => {
           setLayoutVersion(v => v + 1);
       });
    });

    observer.observe(containerRef.current);
    return () => observer.disconnect();
  }, []);

  // Calculate paths for ALL connections (Sequence Black & Decision Red)
  useLayoutEffect(() => {
    if (!containerRef.current) return;

    const paths: React.ReactNode[] = [];
    const containerRect = containerRef.current.getBoundingClientRect();

    data.steps.forEach((step, index) => {
        const sourceColIdx = data.executorColumns.indexOf(step.executorRole);
        if (sourceColIdx === -1) return;
        const sourceId = `node-${index}-${sourceColIdx}`;
        const sourceEl = document.getElementById(sourceId);

        if (!sourceEl) return;
        const srcRect = sourceEl.getBoundingClientRect();

        // ---------------------------------------------------------
        // 1. BLACK ARROW (Sequence: Step N -> Step N+1)
        // ---------------------------------------------------------
        if (index < data.steps.length - 1) {
            const nextStep = data.steps[index + 1];
            const targetColIdx = data.executorColumns.indexOf(nextStep.executorRole);
            const targetId = `node-${index + 1}-${targetColIdx}`;
            const targetEl = document.getElementById(targetId);

            if (targetEl) {
                const tgtRect = targetEl.getBoundingClientRect();

                // Start: Bottom Center of Source
                const startX = srcRect.left + (srcRect.width / 2) - containerRect.left;
                const startY = srcRect.bottom - containerRect.top;

                // End: Top Center of Target
                const endX = tgtRect.left + (tgtRect.width / 2) - containerRect.left;
                const endY = tgtRect.top - containerRect.top;
                const finalY = endY - 10; // Stop 10px before target for arrowhead

                // Path Logic: Down -> Horizontal -> Down
                // Move horizontal immediately after source to drop down INSIDE the target column
                const distY = finalY - startY;
                const midY = startY + Math.min(Math.abs(distY) / 2, 20); // Turn 20px below source

                let d = `M ${startX} ${startY} `;

                // If practically in the same column
                if (Math.abs(startX - endX) < 2) {
                    d += `L ${endX} ${finalY}`;
                } else {
                    // S-Curve (Orthogonal)
                    d += `L ${startX} ${midY} L ${endX} ${midY} L ${endX} ${finalY}`;
                }

                paths.push(
                    <g key={`seq-${index}`}>
                        <path 
                            d={d}
                            fill="none"
                            stroke="black"
                            strokeWidth="2"
                            markerEnd="url(#arrowhead-black)"
                        />
                        {step.symbol === SymbolType.DECISION && (
                             <foreignObject x={startX + 2} y={startY} width="30" height="20">
                                <div className="bg-white/80 text-[8px] font-bold text-green-700 leading-none px-1">
                                    YA
                                </div>
                            </foreignObject>
                        )}
                    </g>
                );
            }
        }

        // ---------------------------------------------------------
        // 2. RED ARROW (Decision: Step N -> Target Row)
        // ---------------------------------------------------------
        if (step.symbol === SymbolType.DECISION && step.decisionNoTargetRow) {
            const targetIndex = parseInt(step.decisionNoTargetRow) - 1;
            if (targetIndex >= 0 && targetIndex < data.steps.length) {
                const targetStep = data.steps[targetIndex];
                const targetColIdx = data.executorColumns.indexOf(targetStep.executorRole);
                const targetId = `node-${targetIndex}-${targetColIdx}`;
                const targetEl = document.getElementById(targetId);
                const sourceTd = sourceEl.closest('td');

                if (targetEl && sourceTd) {
                    const tgtRect = targetEl.getBoundingClientRect();
                    const tdRect = sourceTd.getBoundingClientRect();

                    const isLastCol = sourceColIdx === data.executorColumns.length - 1;

                    // Start from Side (Left or Right based on position)
                    const decisionStartY = srcRect.top + (srcRect.height / 2) - containerRect.top;
                    const decisionStartX = isLastCol 
                        ? srcRect.left - containerRect.left
                        : srcRect.right - containerRect.left;

                    // End: Top Center of Target
                    const endX = tgtRect.left + (tgtRect.width / 2) - containerRect.left;
                    const endY = tgtRect.top - containerRect.top;
                    const finalY = endY - 10;

                    // Calculate Channel X (The vertical line X)
                    // CONSTRAINT: Must stay within the source column boundaries (tdRect)
                    let channelX: number;
                    const channelGap = 15; // Tight gap to avoid spilling

                    if (isLastCol) {
                        // Exit Left: Clamp to ensure we don't go left of the cell
                        const minX = tdRect.left - containerRect.left + 5; 
                        const idealX = decisionStartX - channelGap;
                        channelX = Math.max(minX, idealX);
                    } else {
                        // Exit Right: Clamp to ensure we don't go right of the cell
                        const maxX = tdRect.right - containerRect.left - 5;
                        const idealX = decisionStartX + channelGap;
                        channelX = Math.min(maxX, idealX);
                    }

                    const verticalTargetY = endY - 20; // The horizontal line above the target row

                    let d = `M ${decisionStartX} ${decisionStartY} 
                             L ${channelX} ${decisionStartY}
                             L ${channelX} ${verticalTargetY}
                             L ${endX} ${verticalTargetY}
                             L ${endX} ${finalY}`;

                    paths.push(
                        <g key={`dec-${index}`}>
                            <path 
                                d={d}
                                fill="none"
                                stroke="#EF4444"
                                strokeWidth="2"
                                markerEnd="url(#arrowhead-red)"
                            />
                            {/* "TIDAK" Label */}
                            <foreignObject 
                                x={isLastCol ? channelX - 45 : decisionStartX + 2} 
                                y={decisionStartY - 15} 
                                width="40" 
                                height="20"
                            >
                                <div className="bg-white/80 text-[8px] font-bold text-red-600 leading-none px-1 text-center">
                                    TIDAK
                                </div>
                            </foreignObject>
                             {/* Target Label Bubble */}
                            <foreignObject 
                                x={channelX + (isLastCol ? -65 : 2)} 
                                y={(decisionStartY + verticalTargetY)/2} 
                                width="60" 
                                height="20"
                            >
                                <div className="bg-red-100/80 border border-red-200 text-red-800 text-[8px] px-1 rounded whitespace-nowrap w-max">
                                     Ke No {targetIndex + 1}
                                </div>
                            </foreignObject>
                        </g>
                    );
                }
            }
        }
    });

    setConnectionPaths(paths);
  }, [data, data.steps, data.executorColumns, dragState.isDragging, layoutVersion]); 

  // Handle Global Drag Events
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (dragState.isDragging) {
        setDragState(prev => ({
          ...prev,
          currentX: e.clientX,
          currentY: e.clientY
        }));
      }
    };

    const handleMouseUp = () => {
      if (dragState.isDragging) {
        if (hoveredRowIndex !== null && dragState.sourceIndex !== null) {
            const targetStr = (hoveredRowIndex + 1).toString();
            updateStep(dragState.sourceIndex, 'decisionNoTargetRow', targetStr);
        }
        setDragState({
            isDragging: false,
            sourceIndex: null,
            startX: 0,
            startY: 0,
            currentX: 0,
            currentY: 0,
        });
        setHoveredRowIndex(null);
      }
    };

    if (dragState.isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [dragState.isDragging, hoveredRowIndex, dragState.sourceIndex]);


  const updateField = (field: keyof SOPData, value: any) => {
    onChange({ ...data, [field]: value });
  };

  const updateStep = (index: number, field: string, value: string) => {
    const newSteps = [...data.steps];
    newSteps[index] = { ...newSteps[index], [field]: value };
    updateField('steps', newSteps);
  };

  const updateExecutorColumn = (index: number, value: string) => {
    const oldName = data.executorColumns[index];
    const newCols = [...data.executorColumns];
    newCols[index] = value;

    // Also update steps that were assigned to the old name
    const newSteps = data.steps.map(step => {
        if (step.executorRole === oldName) {
            return { ...step, executorRole: value };
        }
        return step;
    });

    onChange({ ...data, executorColumns: newCols, steps: newSteps });
  };

  const addExecutorColumn = () => {
    const newColName = `Pelaksana ${data.executorColumns.length + 1}`;
    onChange({ ...data, executorColumns: [...data.executorColumns, newColName] });
  };

  const removeExecutorColumn = (index: number) => {
    if (data.executorColumns.length <= 1) {
        alert("Minimal harus ada 1 kolom pelaksana.");
        return;
    }
    const colToRemove = data.executorColumns[index];
    const newCols = data.executorColumns.filter((_, i) => i !== index);

    // If steps are in the removed column, move them to the first available column
    const fallbackCol = newCols[0];
    const newSteps = data.steps.map(step => {
        if (step.executorRole === colToRemove) {
            return { ...step, executorRole: fallbackCol };
        }
        return step;
    });

    onChange({ ...data, executorColumns: newCols, steps: newSteps });
  };

  const handleLogoClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateField('logoUrl', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const startDrag = (e: React.MouseEvent, index: number) => {
    e.stopPropagation();
    e.preventDefault();
    setDragState({
        isDragging: true,
        sourceIndex: index,
        startX: e.clientX,
        startY: e.clientY,
        currentX: e.clientX,
        currentY: e.clientY
    });
  };

  const renderDragHandle = (step: any, currentIndex: number) => {
    if (step.symbol !== SymbolType.DECISION) return null;

    return (
        <div 
            className="no-print absolute top-1/2 -right-4 w-6 h-6 z-40 flex items-center justify-center cursor-grab active:cursor-grabbing group hover:scale-110 transition-transform"
            onMouseDown={(e) => startDrag(e, currentIndex)}
            title="Tarik untuk menghubungkan 'TIDAK'"
        >
             <div className="w-3 h-3 bg-red-500 rounded-full border-2 border-white shadow-sm ring-1 ring-red-400"></div>
        </div>
    );
  };

  return (
    <div className="relative">
    {/* Drag Overlay Line */}
    {dragState.isDragging && (
        <div className="fixed inset-0 z-[9999] pointer-events-none">
             <svg className="w-full h-full">
                <defs>
                    <marker id="drag-arrow-head" markerWidth="10" markerHeight="7" refX="10" refY="3.5" orient="auto">
                        <polygon points="0 0, 10 3.5, 0 7" fill="#EF4444" />
                    </marker>
                 </defs>
                 <line 
                    x1={dragState.startX} 
                    y1={dragState.startY} 
                    x2={dragState.currentX} 
                    y2={dragState.currentY} 
                    stroke="#EF4444" 
                    strokeWidth="2" 
                    strokeDasharray="5,5"
                    markerEnd="url(#drag-arrow-head)"
                 />
             </svg>
             <div 
                className="absolute bg-red-600 text-white text-xs px-2 py-1 rounded shadow-lg transform -translate-x-1/2 -translate-y-full"
                style={{ top: dragState.currentY - 10, left: dragState.currentX }}
             >
                {hoveredRowIndex !== null ? `Lepas untuk hubungkan ke Langkah ${hoveredRowIndex + 1}` : 'Tarik ke baris tujuan...'}
             </div>
        </div>
    )}

    <div ref={containerRef} className="print-container bg-white shadow-lg max-w-[297mm] mx-auto p-8 text-[12px] leading-tight text-[#0F2854] font-sans relative">

      {/* --- GLOBAL SVG OVERLAY FOR LINES --- */}
      <svg className="absolute inset-0 w-full h-full pointer-events-none z-20 overflow-visible">
          <defs>
            <marker id="arrowhead-red" markerWidth="10" markerHeight="10" refX="0" refY="5" orient="auto" markerUnits="userSpaceOnUse">
                <path d="M0,0 L10,5 L0,10 z" fill="#EF4444" />
            </marker>
            <marker id="arrowhead-black" markerWidth="10" markerHeight="10" refX="0" refY="5" orient="auto" markerUnits="userSpaceOnUse">
                <path d="M0,0 L10,5 L0,10 z" fill="black" />
            </marker>
          </defs>
          {connectionPaths}
      </svg>

      {/* --- HEADER TABLE --- */}
      <table className="w-full border-collapse border border-[#1C4D8D] mb-4 text-[#0F2854]">
        <tbody>
          <tr>
            {/* Logo Section */}
            <td rowSpan={4} className="border border-[#1C4D8D] p-2 w-[20%] text-center align-middle relative">
              <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  accept="image/*" 
                  onChange={handleFileChange} 
              />
              <div 
                  className="flex flex-col items-center justify-center h-full min-h-[100px] cursor-pointer group"
                  onClick={handleLogoClick}
                  title="Klik untuk mengganti logo"
              >
                {data.logoUrl ? (
                    <img src={data.logoUrl} alt="Logo" className="w-16 h-16 object-contain mb-2" />
                ) : (
                    <div className="w-16 h-16 rounded-full border-2 border-[#1C4D8D] flex items-center justify-center mb-2 bg-[#BDE8F5] print:border-[#1C4D8D] group-hover:bg-[#4988C4]/20 transition-colors">
                        <span className="text-[#1C4D8D] font-bold text-[10px] print:text-[#1C4D8D]">UPLOAD LOGO</span>
                    </div>
                )}

                <AutoResizeTextarea
                    className="w-full text-center font-bold text-[#1C4D8D] text-xs bg-transparent border-none focus:ring-0 focus:outline-none print:text-[#1C4D8D] placeholder-[#1C4D8D]/50 resize-none overflow-hidden"
                    value={data.organizationName || "Nama Lembaga/Perusahaan"}
                    onChange={(e: any) => updateField('organizationName', e.target.value)}
                    placeholder="Nama Lembaga/Perusahaan"
                    onClick={(e) => e.stopPropagation()} 
                />
              </div>
            </td>

            {/* Title Section */}
            <td rowSpan={4} className="border border-[#1C4D8D] p-2 w-[30%] text-center align-middle bg-[#F3F4F6] print:bg-[#F3F4F6]">
                <AutoResizeTextarea
                    className="w-full text-center font-bold text-lg uppercase bg-transparent border-none focus:ring-1 focus:ring-[#1C4D8D] text-[#0F2854] placeholder-gray-400"
                    value={data.department}
                    onChange={(e: any) => updateField('department', e.target.value)}
                    placeholder="BAGIAN..."
                />
            </td>

            {/* Document Details Section */}
            <td className="border border-[#1C4D8D] px-2 py-1 w-[15%] font-semibold bg-[#F3F4F6] text-[#0F2854] print:bg-[#F3F4F6]">No. SOP/Dokumen</td>
            <td className="border border-[#1C4D8D] px-2 py-1 w-[35%]">
               <span className="mr-1 text-[#0F2854]">:</span>
               <input 
