          </tr>
          <tr>
            <td className="border border-[#1C4D8D] px-3 py-1.5 font-semibold bg-[#F1F5F9] text-[#0F2854] print:bg-[#F1F5F9]">Halaman</td>
            <td className="border border-[#1C4D8D] px-3 py-1.5 text-[#0F2854]">
